"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[8506],{4503(e,t,o){o.r(t),o.d(t,{assets:()=>a,contentTitle:()=>r,default:()=>u,frontMatter:()=>h,metadata:()=>n,toc:()=>d});const n=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-22","title":"Discourses \u2014 Book 2, Chapter 22","description":"Book 2 \u2014 Chapter 22","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-22.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-22","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-22","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":23,"frontMatter":{"sidebar_position":23,"title":"Discourses \u2014 Book 2, Chapter 22","sidebar_label":"Book 2, Ch. 22"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 21","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-21"},"next":{"title":"Book 2, Ch. 23","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-23"}}');var s=o(4848),i=o(8453);const h={sidebar_position:23,title:"Discourses \u2014 Book 2, Chapter 22",sidebar_label:"Book 2, Ch. 22"},r="Discourses",a={},d=[{value:"Book 2 \u2014 Chapter 22",id:"book-2--chapter-22",level:2},{value:"On Friendship",id:"on-friendship",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function l(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)("div",{style:{textAlign:"center"},children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,s.jsx)(t.h2,{id:"book-2--chapter-22",children:"Book 2 \u2014 Chapter 22"}),(0,s.jsx)(t.h3,{id:"on-friendship",children:"On Friendship"})]}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,s.jsxs)(o,{open:!0,children:[(0,s.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,s.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,s.jsx)(t.p,{children:'The most sustained treatment of friendship in the Discourses. The argument: you can only truly love what you correctly understand as good. Since most people misidentify the good \u2014 placing it in wealth, pleasure, reputation, other people \u2014 their "love" is inherently unstable. Throw a piece of meat between dogs who were playing contentedly and you see what their friendship was worth. The same with fathers and sons over an inheritance, brothers over a throne, husband and wife over a necklace.'}),(0,s.jsx)(t.p,{children:'Every creature is attached above all to its own interest. When "I" and "mine" are located in the flesh or in external possessions, everything \u2014 friends, parents, gods \u2014 will be sacrificed the moment it conflicts with that interest. Alexander ordered the shrines of Asclepius burned when his beloved died. Eteocles and Polynices, raised together, prayed for each other\'s blood over a kingship.'}),(0,s.jsx)(t.p,{children:"The only basis for genuine friendship is shared location of the good in the will. If two people both understand that the good lies in right judgment and faithful character, then their interests cannot conflict \u2014 because no external thing can be thrown between them that would cause one to harm the other. Shared parentage, years together, oaths \u2014 none of these constitute friendship. The single diagnostic question is: where do they put their interest?"})]}),"\n",(0,s.jsxs)(o,{open:!0,children:[(0,s.jsx)("summary",{children:"Text"}),(0,s.jsx)(t.h2,{id:"text",children:"Text"}),(0,s.jsx)(t.p,{children:"A MAN naturally loves those things in which he is interested. Now do men take an interest in things evil? Certainly not. Do they take interest in what does not concern them? No, they do not. It follows then that they are interested in good things alone, and if interested in them, therefore love them too. Whoever then has knowledge of good things, would know how to love them; but how could one who cannot distinguish"}),(0,s.jsx)(t.p,{children:"good things from evil and things indifferent from both have power to love? Therefore the wise man alone has power to love."}),(0,s.jsx)(t.p,{children:"'Nay, how is this?' says one. 'I am not wise, yet I love my child.'"}),(0,s.jsx)(t.p,{children:"By the gods, I am surprised, to begin with, at your admission that you are not wise. What do you lack? Do you not enjoy sensation, do you not distinguish impressions, do you not supply your body with the food that is suited to it, and with shelter and a dwelling? How is it then that you admit that you are foolish? I suppose because you are often disturbed and bewildered by your impressions, and overcome by their persuasive powers, so that the very things that at one moment you consider good you presently consider bad and afterwards indifferent; and, in a word, you are subject to pain, fear, envy, confusion, change: that is why you confess yourself to be foolish. And do you not change in your affections? Do you believe at one time that wealth and pleasure and mere outward things are good, and at another time that they are evil, and do you not regard the same persons now as good, now as bad, and sometimes feel friendly towards them, sometimes unfriendly, and now praise, now blame them?"}),(0,s.jsx)(t.p,{children:"'Yes. I am subject to these feelings.'"}),(0,s.jsx)(t.p,{children:"Well then; do you think a man can be a friend to anything about which he is deceived?"}),(0,s.jsx)(t.p,{children:"'Not at all.'"}),(0,s.jsx)(t.p,{children:"Nor can he whose choice of a friend is subject to change bear good will to him?"}),(0,s.jsx)(t.p,{children:"'No, he cannot.'"}),(0,s.jsx)(t.p,{children:"Can he who first reviles a man and then admires him?"}),(0,s.jsx)(t.p,{children:"'No, he cannot.'"}),(0,s.jsx)(t.p,{children:"Again, did you never see curs fawning on one another and playing with one another, so that you say nothing could be friendlier? But to see what friendship is, throw a piece of meat among them and you will learn. So with you and your dear boy: throw a bit of land between you, and you will learn how your boy wishes to give you a speedy burial, and you pray for the boy to die. Then you cry out again, 'What a child I have reared! He is impatient to bury me'. Throw a pretty maid between you and suppose you both love her, you the old man, and he the young man. Or suppose you throw a bit of glory between you. And if you have to risk your life, you will use the words of Admetus' father:"}),(0,s.jsx)(t.p,{children:"You love the light; shall not your father love it?"}),(0,s.jsx)(t.p,{children:"[Euripides, Alcestis, 691]"}),(0,s.jsx)(t.p,{children:"[paragraph continues] Do you think that he did not love his own child when it was small, and was not distressed when it had the fever, and did not often say, 'Would"}),(0,s.jsx)(t.p,{children:"it were I who had the fever instead!'? yet when the event came close upon him, see what words they utter! Were not Eteocles and Polynices born of the same mother and the same father? Were they not reared together, did they not live together, drink together, sleep together, often kiss one another, so that if one had seen them he would, no doubt, have laughed at the paradoxes of philosophers on friendship. Yet when the bit of meat, in the shape of a king's throne, fell between them, see what they say:"}),(0,s.jsx)(t.p,{children:"E. Where wilt stand upon the tower?"}),(0,s.jsx)(t.p,{children:"P. Wherefore dost thou ask me this?"}),(0,s.jsx)(t.p,{children:"E. I will face thee then and slay thee."}),(0,s.jsx)(t.p,{children:"P. I desire thy blood no less."}),(0,s.jsx)(t.p,{children:"[Euripides, The Phoenissae, 621]"}),(0,s.jsx)(t.p,{children:"[paragraph continues] Yes, such are the prayers they utter!"}),(0,s.jsx)(t.p,{children:"For be not deceived, every creature, to speak generally, is attached to nothing so much as to its own interest. Whatever then seems to hinder his way to this, be it a brother or a father or a child, the object of his passion or his own lover, he hates him, guards against him, curses him. For his nature is to love nothing so much as his own interest; this is his father and brother and kinsfolk and country and god. At any rate, when the gods seem to hinder us in regard to this we revile even the gods and overthrow their statues and set fire to their temples, as Alexander ordered the shrines of Asclepius to be burnt when the object of his passion died. Therefore if interest, religion and honour, country, parents and friends are set in the same scale, then all are safe; but if interest is in one scale, and in the other friends and country and kindred and justice itself, all these are weighed down by interest and disappear. For the creature must needs incline to that side where 'I' and 'mine' are; if they are in the flesh, the ruling power must be there; if in the will, it must be there; if in external things, it must be there."}),(0,s.jsx)(t.p,{children:"If then I identify myself with my will, then and only then shall I be a friend and son and father in the true sense. For this will be my interest--to guard my character for good faith, honour, forbearance, self-control, and service of others, to maintain my relations with others. But if I separate myself from what is noble, then Epicurus' statement is confirmed, which declares that 'there is no such thing as the noble or at best it is but the creature of opinion'."}),(0,s.jsx)(t.p,{children:"It was this ignorance that made the Athenians and Lacedaemonians quarrel with one another, and the Thebans with both, and the Great King with Hellas, and the Macedonians with Hellas and the King, and now the Romans with the Getae; and yet earlier this was the reason of the wars with Ilion. Paris was the guest of Menelaus, and any one who"}),(0,s.jsx)(t.p,{children:"had seen the courtesies they used to one another would not have believed one who denied that they were friends. But a morsel was thrown between them, in the shape of a pretty woman, and for that there was war! So now, when you see friends or brothers who seem to be of one mind, do not therefore pronounce upon their friendship, though they swear to it and say it is impossible for them to part with one another. The Governing Principle of the bad man is not to be trusted; it is uncertain, irresolute, conquered now by one impression, now by another. The question you must ask is, not what others ask, whether they were born of the same parents and brought up together and under the charge of the same slave; but this question only, where they put their interest--outside them or in the will. If they put it outside, do not call them friends, any more than you can call them faithful, or stable, or confident, or free; nay, do not call them even men, if you are wise. For it is no human judgement which makes them bite one another and revile one another and occupy deserts or market-places like wild beasts and behave like robbers in the law-courts; and which makes them guilty of profligacy and adultery and seduction and the other offences men commit against one another. There is one judgement and one only which is responsible for all this--that they set themselves and all their interests elsewhere than in their will. But if you hear that these men in very truth believe the good to lie only in the region of the will and in dealing rightly with impressions, you need trouble yourself no more as to whether a man is son or father, whether they are brothers, or have been familiar companions for years; I say, if you grasp this one fact and no more, you may pronounce with confidence that they are friends, as you may that they are faithful and just. For where else is friendship but where faith and honour are, where men give and take what is good, and nothing else?"}),(0,s.jsx)(t.p,{children:"'But he has paid me attention all this time: did he not love me?'"}),(0,s.jsx)(t.p,{children:"How do you know, slave, whether he has paid you this attention, as a man cleans his boots, or tends his beast? How do you know whether, when you have lost your use as a paltry vessel, he will not throw you away like a broken plate?"}),(0,s.jsx)(t.p,{children:"'But she is my wife and we have lived together this long time.'"}),(0,s.jsx)(t.p,{children:"How long did Eriphyle live with Amphiaraus, ay, and was mother of many children?--But a necklace came between them."}),(0,s.jsx)(t.p,{children:"'What do you mean by a necklace?'"}),(0,s.jsx)(t.p,{children:"Man's judgement about good and evil. This was the brutish element, this was what broke up the friendship, which suffered not the wife to be true to her wedlock, nor the mother to be a mother indeed. So let every one of you, who is anxious himself to be friend to another, or to win another for his friend, uproot these judgements, hate them, drive"}),(0,s.jsx)(t.p,{children:"them out of his mind. If he does that, then first he will never revile himself or be in conflict with himself, he will be free from change of mind, and self-torture; secondly he will be friendly to his neighbour, always and absolutely, if he be like himself, and if he be unlike, he will bear with him, be gentle and tender with him, considerate to him as one who is ignorant and in error about the highest matters; not hard upon any man, for he knows of a certainty Plato's saying, 'No soul is robbed of the truth save involuntarily'."}),(0,s.jsx)(t.p,{children:"But if you fail to do this, you may do everything else that friends do --drink together and live under the same roof and sail in the same ship and be born of the same parents; well, the same may be true of snakes, but neither they nor you will be capable of friendship so long as you retain these brutish and revolting judgements."})]})]})}function u(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},8453(e,t,o){o.d(t,{R:()=>h,x:()=>r});var n=o(6540);const s={},i=n.createContext(s);function h(e){const t=n.useContext(i);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:h(e.components),n.createElement(i.Provider,{value:t},e.children)}}}]);